import React, { useEffect, useState } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const generateToken = () => {
  return Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
};

const App = () => {
  const [token, setToken] = useState(null);

  const storeToken = async (newToken) => {
    try {
      await AsyncStorage.setItem('sessionToken', newToken);
      setToken(newToken);
    } catch (error) {
      Alert.alert('Error', 'Failed to store token');
    }
  };

  const retrieveToken = async () => {
    try {
      const storedToken = await AsyncStorage.getItem('sessionToken');
      if (storedToken) {
        setToken(storedToken);
      }
    } catch (error) {
      Alert.alert('Error', 'Failed to retrieve token');
    }
  };

  const handleOfflineAction = () => {
    const newToken = generateToken();
    storeToken(newToken);
    Alert.alert('Token Generated', `Your session token is: ${newToken}`);
  };

  useEffect(() => {
    retrieveToken();
  }, []);

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      <Text>Current Session Token: {token || 'No token generated'}</Text>
      <Button title="Generate Offline Token" onPress={handleOfflineAction} />
    </View>
  );
};

export default App;